# ===== EYES =====
def draw_both_eyes(pdx, color):
    for row in range(EH):
        ry_l = LY - EH//2 + row
        ry_r = RY - EH//2 + row
        dy = row - EH//2
        if row < ER:
            corner_dx = int(math.sqrt(ER*ER - (ER - row)**2))
        elif row >= EH - ER:
            corner_dx = int(math.sqrt(ER*ER - (ER - (EH - row - 1))**2))
        else:
            corner_dx = ER
        rx_start_l = LX - EW//2 + ER - corner_dx
        rx_start_r = RX - EW//2 + ER - corner_dx
        rx_width = EW - 2*(ER - corner_dx)
        tft.hline(rx_start_l, ry_l, rx_width, color)
        tft.hline(rx_start_r, ry_r, rx_width, color)
        pr2 = PR*PR - dy*dy
        if pr2 >= 0:
            pdx2 = int(math.sqrt(pr2))
            px_s = max(LX + pdx - pdx2, rx_start_l)
            px_e = min(LX + pdx + pdx2, rx_start_l + rx_width)
            if px_e > px_s:
                tft.hline(px_s, ry_l, px_e - px_s, gc9a01.BLACK)
            px_s = max(RX + pdx - pdx2, rx_start_r)
            px_e = min(RX + pdx + pdx2, rx_start_r + rx_width)
            if px_e > px_s:
                tft.hline(px_s, ry_r, px_e - px_s, gc9a01.BLACK)
        if 0 <= dy + PR//3 <= 2:
            gx_l = LX + pdx + PR//3
            gx_r = RX + pdx + PR//3
            if rx_start_l <= gx_l <= rx_start_l + rx_width:
                tft.hline(gx_l, ry_l, 3, gc9a01.WHITE)
            if rx_start_r <= gx_r <= rx_start_r + rx_width:
                tft.hline(gx_r, ry_r, 3, gc9a01.WHITE)

def blink(pdx=0):
    for h in range(0, EH//2 + 1, 4):
        tft.fill_rect(LX - EW//2, LY - EH//2, EW, h, gc9a01.BLACK)
        tft.fill_rect(LX - EW//2, LY + EH//2 - h, EW, h, gc9a01.BLACK)
        tft.fill_rect(RX - EW//2, RY - EH//2, EW, h, gc9a01.BLACK)
        tft.fill_rect(RX - EW//2, RY + EH//2 - h, EW, h, gc9a01.BLACK)
        time.sleep_ms(30)
    time.sleep_ms(80)
    draw_both_eyes(pdx, gc9a01.GREEN)

# ===== ANIMATIONS =====
def robot_animation():
    tft.fill(gc9a01.BLACK)
    draw_both_eyes(0, gc9a01.GREEN)
    time.sleep_ms(600)
    blink(-14); time.sleep_ms(400)
    blink(14);  time.sleep_ms(400)
    blink(0);   time.sleep_ms(400)
    tft.fill(gc9a01.BLACK)

def kritish_animation():
    tft.fill(gc9a01.BLACK)
    name = "KRITISH"
    x = center_x(name)
    for i in range(len(name)):
        tft.text(font, name[:i+1], x, 104, gc9a01.GREEN, gc9a01.BLACK)
        time.sleep_ms(150)
    time.sleep(1)
    tft.fill(gc9a01.BLACK)

# ===== WIFI & WEATHER =====
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(WIFI_SSID, WIFI_PASS)
    msg = "WiFi..."
    tft.text(font, msg, center_x(msg), 110, gc9a01.CYAN, gc9a01.BLACK)
    for _ in range(20):
        if wlan.isconnected():
            return True
        time.sleep(0.5)
    return False

def get_weather():
    try:
        url = "http://api.openweathermap.org/data/2.5/weather?q={}&appid={}&units=metric".format(CITY, API_KEY)
        res = urequests.get(url)
        data = res.json()
        res.close()
        temp = str(int(data["main"]["temp"])) + "C"
        desc = data["weather"][0]["main"]
        if len(desc) > 10:
            desc = desc[:10]
        return temp, desc
    except:
        return "--C", "N/A"

# ===== DISPLAY =====# 

def draw_display(h, m, s, date_str, temp, desc, first):
    if first:
        tft.fill(gc9a01.BLACK)
        draw_wifi_icon(185, 45, gc9a01.CYAN)
        draw_icon(45, 145)
    
    # 1. Update Time (Using background color parameter to prevent flicker)
    time_str = "{:02d}:{:02d}:{:02d}".format(h, m, s)
    # Passing BLACK as the background color eliminates the need for fill_rect
    tft.text(font, time_str, center_x(time_str), 95, gc9a01.CYAN, gc9a01.BLACK)

    # 2. Update Date (Only really needs to update once a day, but here is fine)
    tft.text(font, date_str, center_x(date_str), 118, gc9a01.WHITE, gc9a01.BLACK)

    # 3. Update Weather
    weather_str = "{:<4} {:<10}".format(temp, desc)
    tft.text(font, weather_str, 85, 155, gc9a01.YELLOW, gc9a01.BLACK)

# ===== MAIN =====
robot_animation()
kritish_animation()

if connect_wifi():
    try:
        ntptime.settime()
    except:
        pass

# Initial weather fetch
temp, desc = get_weather()
last_weather_update = time.time()
prev_s = -1
first_run = True

while True:
    current_ts = time.time()
    t = current_ts + IST_OFFSET
    tm = time.gmtime(t)
    h, m, s = tm[3], tm[4], tm[5]
    
    # Check if a second has actually passed
    if prev_s != s:
        date_str = "{:02d} {} {}".format(tm[2], MONTHS[tm[1]-1], tm[0])
        
        # Periodic Weather Update (Every 10 minutes)
        if current_ts - last_weather_update >= 600:
            temp, desc = get_weather()
            last_weather_update = current_ts
            
        draw_display(h, m, s, date_str, temp, desc, first_run)
        prev_s = s
        first_run = False

    time.sleep_ms(100) # Faster polling for better responsiveness

